    public synchronized int waitUntilOK2Connect() {
        boolean interruptd= false;
        int idx = -1;




        while (curconn>=MAXCONN) {
            try {
                wait();
            } catch (InterruptedException e) { interruptd = true; }
        }



        if (!interruptd) {

            curconn++;
            for (idx=0;idx<MAXCONN;idx++)
                if (!connused[idx]) {
                    connused[idx] = true;
                    break;
                }

            notifyAll();
        }


        return idx;
    }


