    public static void countIdxLimit() {
        idxLimit = new int[MAXCHAR+1];

        NCHAR    = charset.length();
        ALLCOMBI = 0;
        for (int i=0;i<=MAXCHAR;i++) {
            if (i==0) {
                idxLimit[i] = 0;
            } else {
                idxLimit[i] = idxLimit[i-1] + Math.pow(NCHAR,i);
            }
        }

        ALLCOMBI = idxLimit[idxLimit.length-1];
    }


